let data;
try {
    data = JSON.parse(msg.payload);
} catch(e) {
    node.warn('Payload não é JSON válido: ' + msg.payload);
    return null;
}

// Extrai campos do JSON publicado pelo ESP32
msg.temperatura      = data.temperatura;
msg.temperatura_alvo = data.temperatura_alvo;
msg.ssr_state        = data.ssr_state;
msg.potencia_esp_w   = data.potencia_esp_w;
msg.energia_esp_wh   = data.energia_esp_wh;
msg.sensor           = data.sensor || 'DS18B20';

return msg;

const temp = parseFloat(msg.temperatura);
const MIN = parseFloat(env.get('SENSOR_TEMP_MIN') || '-55');
const MAX = parseFloat(env.get('SENSOR_TEMP_MAX') || '125');

if (isNaN(temp) || temp < MIN || temp > MAX) {
    node.warn('Leitura inválida: ' + temp);
    node.status({fill:'red', shape:'ring', text:'inválida: '+temp});
    const evMsg = {
        payload: [[
            new Date().toISOString(),
            'SENSOR_INVALID',
            'Valor fora do range: ' + temp,
            'n-validate'
        ]],
        spreadsheetId: env.get('SHEETS_SPREADSHEET_ID'),
        sheetName: env.get('SHEETS_TAB_EVENTS') || 'event_logs',
        range: (env.get('SHEETS_TAB_EVENTS') || 'event_logs') + '!A:D'
    };
    node.send([null, evMsg]);
    return null;
}

const ts  = new Date().toISOString();
const tab = env.get('SHEETS_TAB_READINGS') || 'sensor_readings';

global.set('last_temp', temp);
global.set('last_reading_ts', Date.now());
global.set('total_readings', (global.get('total_readings') || 0) + 1);

// Linha para o Sheets:
// timestamp | temperatura | sensor | temperatura_alvo | ssr_state | potencia_esp_w | energia_esp_wh
msg.timestamp     = ts;
msg.temperature   = temp;
msg.payload       = [[
    ts,
    temp,
    msg.sensor || 'DS18B20',
    msg.temperatura_alvo,
    msg.ssr_state,
    msg.potencia_esp_w,
    msg.energia_esp_wh
]];
msg.sheets_data   = msg.payload;
msg.spreadsheetId = env.get('SHEETS_SPREADSHEET_ID');
msg.sheetName     = tab;
msg.range         = tab + '!A:G';
msg._attempts     = 0;

node.status({fill:'green', shape:'dot', text: temp + '°C | ssr:' + msg.ssr_state});
return [msg, null];

const MAX_Q = parseInt(env.get('QUEUE_MAX_SIZE') || '500');
const queue  = flow.get('queue') || [];

if (!msg._fromRetry) {
    if (queue.length >= MAX_Q) {
        node.warn('Fila cheia! Descartando: ' + msg.timestamp);
        const evMsg = {
            payload: [[
                new Date().toISOString(),
                'QUEUE_OVERFLOW',
                'Fila cheia (' + MAX_Q + '). Leitura descartada: ' + msg.timestamp,
                'n-queue-add'
            ]],
            spreadsheetId: env.get('SHEETS_SPREADSHEET_ID'),
            sheetName: env.get('SHEETS_TAB_EVENTS') || 'event_logs',
            range: (env.get('SHEETS_TAB_EVENTS') || 'event_logs') + '!A:D'
        };
        node.send([null, evMsg]);
        return null;
    }
    queue.push({
        sheets_data:   msg.sheets_data,
        timestamp:     msg.timestamp,
        temperature:   msg.temperature,
        spreadsheetId: msg.spreadsheetId,
        sheetName:     msg.sheetName,
        range:         msg.range,
        attempts:      0
    });
    flow.set('queue', queue);
}

const item = queue[0];
if (!item) return null;

msg.sheets_data   = item.sheets_data;
msg.timestamp     = item.timestamp;
msg.temperature   = item.temperature;
msg.spreadsheetId = item.spreadsheetId;
msg.sheetName     = item.sheetName;
msg.range         = item.range;
msg._attempts     = item.attempts;
msg.payload       = item.sheets_data;

node.status({fill:'blue', shape:'ring', text:'fila: ' + queue.length});
return [msg, null];

const queue = flow.get('queue') || [];
queue.shift();
flow.set('queue', queue);
node.status({fill:'green', shape:'dot', text:'OK | fila: ' + queue.length});
return msg;

const RETRY_MAX   = parseInt(env.get('RETRY_MAX_ATTEMPTS') || '5');
const RETRY_DELAY = parseInt(env.get('RETRY_DELAY_MS')      || '60000');

const queue = flow.get('queue') || [];
const item  = queue[0];
if (!item) return null;

item.attempts = (item.attempts || 0) + 1;
flow.set('queue', queue);
global.set('total_errors', (global.get('total_errors') || 0) + 1);

const evRetry = {
    payload: [[
        new Date().toISOString(),
        'SHEETS_RETRY',
        'Tentativa ' + item.attempts + '/' + RETRY_MAX + ' | ' + item.timestamp,
        'n-retry'
    ]],
    spreadsheetId: env.get('SHEETS_SPREADSHEET_ID'),
    sheetName: env.get('SHEETS_TAB_EVENTS') || 'event_logs',
    range: (env.get('SHEETS_TAB_EVENTS') || 'event_logs') + '!A:D'
};

if (item.attempts >= RETRY_MAX) {
    node.warn('Fallback CSV: ' + item.timestamp);
    queue.shift();
    flow.set('queue', queue);

    const row = item.sheets_data[0];
    const csvLine = row.join(',') + '\n';
    const csvLines = (global.get('csv_buffer_lines') || 0) + 1;
    global.set('csv_buffer_lines', csvLines);

    const csvMsg = {
        payload:  csvLine,
        filename: env.get('BUFFER_CSV_PATH') || '/data/buffer.csv'
    };

    const evFallback = {
        payload: [[
            new Date().toISOString(),
            'SHEETS_FALLBACK_CSV',
            'Max tentativas atingido. Salvo em CSV. Leitura: ' + item.timestamp,
            'n-retry'
        ]],
        spreadsheetId: env.get('SHEETS_SPREADSHEET_ID'),
        sheetName: env.get('SHEETS_TAB_EVENTS') || 'event_logs',
        range: (env.get('SHEETS_TAB_EVENTS') || 'event_logs') + '!A:D'
    };

    node.status({fill:'red', shape:'ring', text:'CSV fallback | fila: ' + queue.length});
    node.send([null, csvMsg, evFallback]);
    return null;
}

const retryMsg = {
    payload:       item.sheets_data,
    sheets_data:   item.sheets_data,
    timestamp:     item.timestamp,
    temperature:   item.temperature,
    spreadsheetId: item.spreadsheetId,
    sheetName:     item.sheetName,
    range:         item.range,
    _attempts:     item.attempts,
    _fromRetry:    true
};
node.status({fill:'yellow', shape:'ring', text:'retry ' + item.attempts + '/' + RETRY_MAX});
setTimeout(() => { node.send([retryMsg, null, evRetry]); }, RETRY_DELAY);
return null;

const ts = new Date().toISOString();
const status = msg.status || {};
const fill   = status.fill  || 'grey';
const text   = status.text  || '';

let eventType = 'MQTT_STATUS';
if (fill === 'green' || text.toLowerCase().includes('connect')) {
    eventType = 'MQTT_CONNECTED';
} else if (fill === 'red' || text.toLowerCase().includes('disconnect') || text.toLowerCase().includes('error')) {
    eventType = 'MQTT_DISCONNECTED';
}

msg.payload = [[
    ts,
    eventType,
    text || 'Status: ' + fill,
    'mqtt-broker'
]];
msg.spreadsheetId = env.get('SHEETS_SPREADSHEET_ID');
msg.sheetName     = env.get('SHEETS_TAB_EVENTS') || 'event_logs';
msg.range         = (env.get('SHEETS_TAB_EVENTS') || 'event_logs') + '!A:D';

return msg;

const ts             = new Date().toISOString();
const queue          = flow.get('queue') || [];
const lastTemp       = global.get('last_temp')        || null;
const lastReadingTs  = global.get('last_reading_ts')  || null;
const totalReadings  = global.get('total_readings')   || 0;
const totalErrors    = global.get('total_errors')     || 0;
const csvLines       = global.get('csv_buffer_lines') || 0;

const ageSeconds = lastReadingTs
    ? Math.floor((Date.now() - lastReadingTs) / 1000)
    : null;

const brokerStatus = (ageSeconds !== null && ageSeconds < 120)
    ? 'connected'
    : 'unknown';

msg.payload = [[
    ts,
    queue.length,
    lastTemp !== null ? lastTemp : 'N/A',
    ageSeconds !== null ? ageSeconds : 'N/A',
    brokerStatus,
    totalReadings,
    totalErrors,
    csvLines
]];

msg.spreadsheetId = env.get('SHEETS_SPREADSHEET_ID');
msg.sheetName     = env.get('SHEETS_TAB_HEALTH') || 'health_logs';
msg.range         = (env.get('SHEETS_TAB_HEALTH') || 'health_logs') + '!A:H';

node.status({fill:'blue', shape:'dot',
    text: 'q:' + queue.length + ' t:' + (lastTemp || '?') + ' err:' + totalErrors});
return msg;
